"""Emission compliance tests for governance (auto-generated by pact)."""

from governance.governance import Governance


class TestEmissionCompliance:
    """Verify governance emits structured events correctly."""

    def _make_handler(self):
        events = []
        return events, lambda event: events.append(event)

    def test_seal_emits_events(self):
        """Method seal emits invoked and completed events."""
        events, handler = self._make_handler()
        obj = Governance(event_handler=handler)
        try:
            obj.seal()
        except (TypeError, Exception):
            pass
        invoked = [e for e in events if e.get("event") == "invoked"]
        completed = [e for e in events if e.get("event") in ("completed", "error")]
        assert len(invoked) >= 1, 'No invoked event for seal'
        assert len(completed) >= 1, 'No completed/error event for seal'
        assert invoked[0].get("pact_key") == "PACT:governance:seal"
        assert isinstance(invoked[0].get("input_classification"), list)

